// // This module implements a 4-to-1 multiplexer with inverted selection logic
module top_module(
  input [3:0] DIN,
  input [1:0] SEL,
  output DOUT
);assign DOUT = (DIN[0] & ~SEL[0] & ~SEL[1]) | (DIN[1] & SEL[0] & ~SEL[1]) | (DIN[2] & ~SEL[0] & SEL[1]) | (DIN[3] & SEL[0] & SEL[1]);
endmodule
